1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
17	
18	const sumBasePremiums = (items: Item[]): number =>
19	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
20	
21	const computePremium = (items: Item[]): number => {
22	  const base = sumBasePremiums(items);
23	  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
24	  return withFirstInsurance + PROCESSING_FEE;
25	};
26	
27	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
28	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
29	const roundUpToGold = (amount: number): number =>
30	  Math.ceil(Math.round(amount * 1e6) / 1e6);
31	
32	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
33	  const results = scenario.steps.map((step) => ({
34	    premium: roundUpToGold(computePremium(step.items)),
35	  }));
36	  return { results };
37	};
